public static bool IsUrlHostnameResolvingToPrivateIp(string url)
{
    string hostname = new Uri(url).Host;
    IPAddress[] ipAddresses = Dns.GetHostAddresses(hostname);
    return ipAddresses.Any(ip => ip.IsPrivateIPAddress());
}

public static bool IsPrivateIPAddress(this IPAddress ipAddress)
{
    return ipAddress.IsIPv4PrivateNetwork() || ipAddress.IsIPv6PrivateNetwork();
}

public static bool IsIPv4PrivateNetwork(this IPAddress ipAddress)
{
    return ipAddress.AddressFamily == System.Net.Sockets.AddressFamily.InterNetwork &&
           (ipAddress.IsInRange(new IPAddress(new byte[] { 10, 0, 0, 0 }), new IPAddress(new byte[] { 10, 255, 255, 255 })) ||
            ipAddress.IsInRange(new IPAddress(new byte[] { 172, 16, 0, 0 }), new IPAddress(new byte[] { 172, 31, 255, 255 })) ||
            ipAddress.IsInRange(new IPAddress(new byte[] { 192, 168, 0, 0 }), new IPAddress(new byte[] { 192, 168, 255, 255 })));
}

public static bool IsIPv6PrivateNetwork(this IPAddress ipAddress)
{
    return ipAddress.AddressFamily == System.Net.Sockets.AddressFamily.InterNetworkV6 &&
           (ipAddress.IsInRange(new IPAddress(new byte[] { 0xfd, 0, 0, 0, 0, 0, 0, 0 }), new IPAddress(new byte[] { 0xfd, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff })) ||
            ipAddress.IsInRange(new IPAddress(new byte[] { 0xfe, 0xc0, 0, 0, 0, 0, 0, 0 }), new IPAddress(new byte[] { 0xfe, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff })) ||
            ipAddress.IsInRange(new IPAddress(new byte[] { 0xfc, 0, 0, 0, 0, 0, 0, 0 }), new IPAddress(new byte[] { 0xfc, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff, 0xff })));
}

public static bool IsInRange(this IPAddress ipAddress, IPAddress rangeStart, IPAddress rangeEnd)
{
    byte[] ipAddressBytes = ipAddress.GetAddressBytes();
    byte[] rangeStartBytes = rangeStart.GetAddressBytes();
    byte[] rangeEndBytes = rangeEnd.GetAddressBytes();

    for (int i = 0; i < ipAddressBytes.Length; i++)
    {
        if (ipAddressBytes[i] < rangeStartBytes[i] || ipAddressBytes[i] > rangeEndBytes[i])
        {
            return false;
        }
    }

    return true;
}

